#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <iostream>
#include <omp.h>

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define M_SEED   9

#define IN_RANGE(x, min, max)	((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

int   rows = -1, cols = -1;
int   Ne = rows * cols;
int*  data;
int** wall;
int*  result;
int   pyramid_height = -1;
int   verbose = 0;

void init(int argc, char** argv)
{
    int cur_arg;
	for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (argc >= cur_arg + 1) {
                pyramid_height = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
			verbose = 1;
        }
    }

	if (cols < 0 || rows < 0 || pyramid_height < 0)
	{
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v]\n", argv[0]);
		exit(0);
	}
	data = new int[rows * cols];
	wall = new int*[rows];
	for (int n = 0; n < rows; n++)
	{
		wall[n] = data + cols * n;
	}
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
	{
		for (int j = 0; j < cols; j++)
		{
			wall[i][j] = rand() % 10;
		}
	}
}

void fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);
}

void dynproc_kernel(int iteration,
                    int* gpuWall,
                    int* gpuSrc,
                    int* gpuResults,
                    int cols,
                    int rows,
                    int startStep,
                    int border,
                    int HALO,
                    int* outputBuffer)
{
	int BLOCK_SIZE = cols;

	int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);

	int blkX = -border;
	int blkXmax = blkX+BLOCK_SIZE-1;

	int* prev = new int[BLOCK_SIZE];
	int* result = new int[BLOCK_SIZE];

	// Load prev from gpuSrc for valid indices
	#pragma omp parallel for
	for (int tx = 0; tx < BLOCK_SIZE; tx++) {
		int xidx = blkX + tx;
		if (IN_RANGE(xidx, 0, cols-1)) {
			prev[tx] = gpuSrc[xidx];
		} else {
			prev[tx] = 0; // safe default
		}
	}

	int validXmin = (blkX < 0) ? -blkX : 0;
	int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

	bool computed = false;

	for (int i = 0; i < iteration; i++)
	{
		computed = false;

		#pragma omp parallel for
		for (int tx = 0; tx < BLOCK_SIZE; tx++) {
			bool isValid = IN_RANGE(tx, validXmin, validXmax);
			if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid )
			{
				computed = true;
				int W = tx-1;
				int E = tx+1;

				W = (W < validXmin) ? validXmin : W;
				E = (E > validXmax) ? validXmax : E;

				int left = prev[W];
				int up = prev[tx];
				int right = prev[E];
				int shortest = MIN(left, up);
				shortest = MIN(shortest, right);

				int xidx = blkX + tx;
				int index = cols*(startStep+i)+xidx;
				result[tx] = shortest + gpuWall[index];

				if (tx==11 && i==0)
				{
					int bufIndex = gpuSrc[xidx];
					outputBuffer[bufIndex] = 1;
				}
			}
		}

		if(i==iteration-1)
		{
			break;
		}

		// Copy result to prev for next iteration
		#pragma omp parallel for
		for (int tx = 0; tx < BLOCK_SIZE; tx++) {
			if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && IN_RANGE(tx, validXmin, validXmax) )
			{
				prev[tx] = result[tx];
			}
		}
	}

	// Write back results
	#pragma omp parallel for
	for (int tx = 0; tx < BLOCK_SIZE; tx++) {
		if( IN_RANGE(tx, validXmin, validXmax) )
		{
			int xidx = blkX + tx;
			if (IN_RANGE(xidx, 0, cols-1))
			{
				gpuResults[xidx] = result[tx];
			}
		}
	}

	delete[] prev;
	delete[] result;
}

int main(int argc, char** argv)
{
	init(argc, argv);

	int borderCols = (pyramid_height) * HALO;

	int size = rows * cols;

	// Initialize gpuResult buffers
	int* gpuResult[2];
	gpuResult[0] = new int[cols];
	gpuResult[1] = new int[cols];

	// Initialize gpuResult[0] with data (first row)
	for (int i = 0; i < cols; i++)
		gpuResult[0][i] = data[i];

	// Initialize outputBuffer
	int* h_outputBuffer = new int[16384];
	for (int i = 0; i < 16384; i++) {
		h_outputBuffer[i] = 0;
	}

	int src = 1, final_ret = 0;

	for (int t = 0; t < rows - 1; t += pyramid_height)
	{
		int temp = src;
		src = final_ret;
		final_ret = temp;

		int arg0 = MIN(pyramid_height, rows - t - 1);
		int theHalo = HALO;

		dynproc_kernel(arg0,
		               &wall[0][0],
		               gpuResult[src],
		               gpuResult[final_ret],
		               cols,
		               rows,
		               t,
		               borderCols,
		               theHalo,
		               h_outputBuffer);
	}

	// Copy final results to result array
	for (int i = 0; i < cols; i++)
		result[i] = gpuResult[final_ret][i];

	h_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
	for (int i = 0; i < cols; i++)
		printf("%d ", data[i]);
	printf("\n");
	for (int i = 0; i < cols; i++)
		printf("%d ", result[i]);
	printf("\n");
#endif

	delete[] data;
	delete[] wall;
	delete[] result;
	delete[] gpuResult[0];
	delete[] gpuResult[1];
	delete[] h_outputBuffer;

	return EXIT_SUCCESS;
}
